#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
#define MAXP 100005
int N, K, P;
int A[MAXN];
int adj[MAXN][MAXN];
void bfs(int start, int end) {
    int visited[MAXN];
    for (int i = 0; i < N; i++) visited[i] = 0;
    int queue[MAXN], front = 0, rear = 0;
    queue[rear++] = start;
    visited[start] = 1;
    while (front < rear) {
        int u = queue[front++];
        if (u == end) {
            printf("Yes\n");
            return;
        }
        for (int v = 0; v < N; v++) {
            if (adj[u][v] && !visited[v]) {
                queue[rear++] = v;
                visited[v] = 1;
            }
        }
    }
    printf("No\n");
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &K, &P);
        for (int i = 0; i < N; i++) scanf("%d", &A[i]);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (i != j && abs(A[i] - A[j]) <= K) {
                    adj[i][j] = 1;
                }
            }
        }
        for (int i = 0; i < P; i++) {
            int a, b;
            scanf("%d %d", &a, &b);
            a--; b--;
            bfs(a, b);
        }
    }
    return 0;
}

